// Middleware to verify 2FA token for protected routes
async function require2FA(req, res, next) {
  const authHeader = req.headers['x-2fa-token'];
  const userId = req.headers['x-user-id'];

  if (!userId || !isValidUserId(userId)) {
    return res.status(401).json({ success: false, message: 'Authentication required.' });
  }

  if (!authHeader || typeof authHeader !== 'string') {
    return res.status(401).json({ success: false, message: '2FA verification required.' });
  }

  try {
    const verifiedKey = VERIFIED_KEY_PREFIX + userId;
    const storedToken = await redisClient.get(verifiedKey);

    if (!storedToken) {
      return res.status(401).json({ success: false, message: '2FA session expired. Please verify again.' });
    }

    // Constant-time comparison
    if (!safeCompare(authHeader, storedToken)) {
      return res.status(401).json({ success: false, message: 'Invalid 2FA token.' });
    }

    req.verifiedUserId = userId;
    next();
  } catch (error) {
    console.error('Error checking 2FA token:', error.message);
    res.status(500).json({ success: false, message: 'Authentication check failed.' });
  }
}

